import os
import json
import time

class APICache:
    def __init__(self, cache_dir='api_cache', expire_time=3600):
        self.cache_dir = cache_dir
        self.expire_time = expire_time
        if not os.path.exists(self.cache_dir):
            os.makedirs(self.cache_dir)

    def _cache_key_to_path(self, key):
        return os.path.join(self.cache_dir, f'{key}.json')

    def _is_expired(self, file_path):
        current_time = time.time()
        file_modified_time = os.path.getmtime(file_path)
        return (current_time - file_modified_time) > self.expire_time

    def get(self, key):
        cache_file = self._cache_key_to_path(key)
        if not os.path.exists(cache_file) or self._is_expired(cache_file):
            return None
        with open(cache_file, 'r') as f:
            return json.load(f)

    def set(self, key, data):
        cache_file = self._cache_key_to_path(key)
        with open(cache_file, 'w') as f:
            json.dump(data, f)

